 Chapter 2 Análisis exploratorio de datos 2.1 Análisis univariado Empezando con la variable objetivo, queremos ver cuantos y cuales paises nos están dando integramente sus datos en la columna tasa_fin, puesto que observabamos que en el dataset no todos los paises brindaban sus datos integramente. # --- Contar países con datos (2000–2022) y su cobertura --- suppressPackageStartupMessages({ library(dplyr) }) # 1) Detectar columnas de país y año según cómo las nombraste cols &lt;- names(df_2) country_col &lt;- if (&quot;pais&quot; %in% cols) &quot;pais&quot; else if (&quot;country&quot; %in% cols) &quot;country&quot; else stop(&quot;No encuentro la columna de país. Esperaba &#39;pais&#39; o &#39;country&#39;.&quot;) year_col &lt;- if (&quot;anio&quot; %in% cols) &quot;anio&quot; else if (&quot;year&quot; %in% cols) &quot;year&quot; else stop(&quot;No encuentro la columna de año. Esperaba &#39;anio&#39; o &#39;year&#39;.&quot;) # 2) Definir el rango de años y filtrar estrictamente 2000–2022 years_target &lt;- 2000:2022 n_years_target &lt;- length(years_target) df_win &lt;- df_2 %&gt;% rename(pais = all_of(country_col), anio = all_of(year_col)) %&gt;% mutate(anio = as.integer(anio)) %&gt;% filter(!is.na(pais), !is.na(anio), anio %in% years_target) # 3) Países únicos con al menos un dato en 2000–2022 n_paises_con_dato &lt;- n_distinct(df_win$pais) # 4) Cobertura por país: cuántos años reporta cada país en el rango coverage_por_pais &lt;- df_win %&gt;% distinct(pais, anio) %&gt;% count(pais, name = &quot;n_anios&quot;) %&gt;% mutate(frac_cobertura = n_anios / n_years_target) # 5) Países con cobertura completa (los 23 años) n_paises_completos &lt;- sum(coverage_por_pais$n_anios == n_years_target) prop_paises_completos &lt;- if (n_paises_con_dato &gt; 0) n_paises_completos / n_paises_con_dato else NA_real_ # 6) Resumen de cobertura (años por país) resumen_cobertura &lt;- coverage_por_pais %&gt;% summarise( paises_con_algun_dato = n(), anios_min = min(n_anios, na.rm = TRUE), anios_p25 = quantile(n_anios, 0.25, na.rm = TRUE), anios_med = median(n_anios, na.rm = TRUE), anios_p75 = quantile(n_anios, 0.75, na.rm = TRUE), anios_max = max(n_anios, na.rm = TRUE) ) # 7) Mostrar resultados clave cat(&quot;Países con al menos un dato (2000–2022):&quot;, n_paises_con_dato, &quot;
&quot;) ## Países con al menos un dato (2000–2022): 192 cat(&quot;Países con cobertura completa (23 años):&quot;, n_paises_completos, sprintf(&quot; (%.1f%%)
&quot;, 100 * prop_paises_completos)) ## Países con cobertura completa (23 años): 30 (15.6%) print(resumen_cobertura) ## paises_con_algun_dato anios_min anios_p25 anios_med anios_p75 anios_max ## 1 192 1 11 17 21 23 En el período 2000–2022 contamos con datos de 192 países, pero la cobertura es heterogénea: solo 30 países (15,6%) reportan la serie completa de 23 años, mientras que el resto presenta huecos. En términos de extensión temporal por país, el mínimo es de 1 año, el p25 es 11, la mediana es 17, el p75 es 21 y el máximo es 23. Estos resultados confirman que trabajamos con un panel desbalanceado; por ello, los análisis temporales y las comparaciones entre países deben considerar esta asimetría de cobertura (p. ej., restringiendo periodos comunes, reportando el número efectivo de observaciones o aplicando estrategias robustas frente a datos faltantes) para evitar sesgos en la interpretación. suppressPackageStartupMessages(library(dplyr)) # --- Detectar nombres de columnas --- cols &lt;- names(df_2) country_col &lt;- if (&quot;pais&quot; %in% cols) &quot;pais&quot; else if (&quot;country&quot; %in% cols) &quot;country&quot; else stop(&quot;No encuentro la columna de país. Esperaba &#39;pais&#39; o &#39;country&#39;.&quot;) year_col &lt;- if (&quot;anio&quot; %in% cols) &quot;anio&quot; else if (&quot;year&quot; %in% cols) &quot;year&quot; else stop(&quot;No encuentro la columna de año. Esperaba &#39;anio&#39; o &#39;year&#39;.&quot;) target_col &lt;- if (&quot;tasa_fin&quot; %in% cols) &quot;tasa_fin&quot; else if (&quot;tasa_fin_prim_fem&quot; %in% cols) &quot;tasa_fin_prim_fem&quot; else if (&quot;SE.PRM.CMPT.FE.ZS&quot; %in% cols) &quot;SE.PRM.CMPT.FE.ZS&quot; else stop(&quot;No encuentro la columna de la variable objetivo. Esperaba &#39;tasa_fin&#39;, &#39;tasa_fin_prim_fem&#39; o &#39;SE.PRM.CMPT.FE.ZS&#39;.&quot;) # --- Filtrar rango temporal y no-NA en la variable objetivo --- df_win &lt;- df_2 %&gt;% rename(pais = all_of(country_col), anio = all_of(year_col), tasa_fin = all_of(target_col)) %&gt;% mutate(anio = as.integer(anio)) %&gt;% filter(anio &gt;= 2000, anio &lt;= 2022, !is.na(tasa_fin)) # 1) Lista de países con al menos un porcentaje reportado (2000–2022) paises_con_porcentaje &lt;- sort(unique(df_win$pais)) # 2) (Útil) Conteo de años reportados por país en el rango conteo_por_pais &lt;- df_win %&gt;% distinct(pais, anio) %&gt;% count(pais, name = &quot;n_anios_reportados&quot;) %&gt;% arrange(desc(n_anios_reportados), pais) # --- Mostrar resultados --- length(paises_con_porcentaje) # cuántos países ## [1] 192 head(paises_con_porcentaje, 20) # primeros 20 países (para inspección rápida) ## [1] &quot;Afghanistan&quot; &quot;Albania&quot; &quot;Algeria&quot; ## [4] &quot;Andorra&quot; &quot;Angola&quot; &quot;Antigua and Barbuda&quot; ## [7] &quot;Argentina&quot; &quot;Armenia&quot; &quot;Aruba&quot; ## [10] &quot;Austria&quot; &quot;Azerbaijan&quot; &quot;Bahamas, The&quot; ## [13] &quot;Bahrain&quot; &quot;Bangladesh&quot; &quot;Barbados&quot; ## [16] &quot;Belarus&quot; &quot;Belize&quot; &quot;Benin&quot; ## [19] &quot;Bermuda&quot; &quot;Bhutan&quot; # Tabla con el conteo por país (puedes imprimir completa o filtrar) head(conteo_por_pais, 20) ## pais n_anios_reportados ## 1 Algeria 23 ## 2 Argentina 23 ## 3 Azerbaijan 23 ## 4 Brunei Darussalam 23 ## 5 Bulgaria 23 ## 6 Cabo Verde 23 ## 7 Cuba 23 ## 8 Cyprus 23 ## 9 Czechia 23 ## 10 Estonia 23 ## 11 Finland 23 ## 12 Germany 23 ## 13 Hungary 23 ## 14 Iceland 23 ## 15 Italy 23 ## 16 Kazakhstan 23 ## 17 Korea, Rep. 23 ## 18 Kyrgyz Republic 23 ## 19 Lao PDR 23 ## 20 Latvia 23 Antes de interpretar las distribuciones gráficas de las variables, es importante considerar una característica metodológica de los datos de WDI. La tasa de finalización primaria puede superar el 100% debido a la forma en que se calcula: el numerador contabiliza a todos los estudiantes que egresan del último grado de primaria, independientemente de su edad, mientras que el denominador corresponde únicamente a la población oficialmente asignada a ese nivel. La presencia de estudiantes en sobredad, subedad o con historial de repetición puede inflar el numerador, generando valores superiores al 100%. Por esta razón, identificamos y revisamos previamente las observaciones que exceden ese umbral y, para mejorar la claridad visual en los gráficos, trabajamos con una versión acotada de la variable en el rango 0–100, conservando la original para efectos de trazabilidad. library(dplyr) library(knitr) # Resumen rápido n_mayor_100 &lt;- sum(df_2$tasa_fin &gt; 100, na.rm = TRUE) prop_mayor_100 &lt;- round(mean(df_2$tasa_fin &gt; 100, na.rm = TRUE) * 100, 2) max_tasa &lt;- max(df_2$tasa_fin, na.rm = TRUE) cat(&quot;Observaciones &gt; 100%:&quot;, n_mayor_100, &quot;
&quot;) ## Observaciones &gt; 100%: 750 cat(&quot;Porcentaje del total:&quot;, prop_mayor_100, &quot;%
&quot;) ## Porcentaje del total: 24.97 % cat(&quot;Valor máximo observado:&quot;, round(max_tasa, 2), &quot;%

&quot;) ## Valor máximo observado: 168.18 % # Top casos &gt; 100% (ordenados de mayor a menor) top_mayor_100 &lt;- df_2 %&gt;% filter(tasa_fin &gt; 100) %&gt;% arrange(desc(tasa_fin)) %&gt;% select(pais, anio, tasa_fin) %&gt;% head(15) kable(top_mayor_100, caption = &quot;Principales observaciones con tasa de finalización &gt; 100%&quot;) Table 2.1: Principales observaciones con tasa de finalización &gt; 100% pais anio tasa_fin Monaco 2016 168.1818 Seychelles 2021 167.0404 Seychelles 2017 155.3047 St. Kitts and Nevis 2021 150.3546 Seychelles 2019 140.8582 Maldives 2005 135.6577 Turkiye 2016 135.3401 Seychelles 2020 133.4992 Belarus 2002 132.8589 Saudi Arabia 2012 131.8461 Turks and Caicos Islands 2018 130.9524 Seychelles 2016 129.5026 Seychelles 2018 128.4734 Maldives 2006 126.8359 Nauru 2016 126.3158 El análisis univariado tiene como propósito examinar cada variable por separado con el fin de comprender su comportamiento general antes de integrar comparaciones entre países o estudiar su evolución temporal. En esta etapa se describen las características básicas de cada columna del dataset df_2, incluyendo medidas de tendencia central, dispersión, rangos, distribución y presencia de valores extremos. Dado que la tasa de finalización primaria puede presentar valores superiores al 100% debido a la metodología utilizada por WDI, y con el fin de mejorar la interpretación visual de las distribuciones, los gráficos correspondientes emplean una versión acotada de la variable objetivo en el intervalo 0–100. Esta decisión no altera los valores originales, que se conservan para su documentación, pero facilita la lectura de los resultados y evita que valores atípicos dominen la escala gráfica. Dado que los datos corresponden a un panel desbalanceado —donde algunos países reportan más años que otros—, estos resultados deben interpretarse como una descripción global del conjunto y no como comparaciones estrictas entre unidades. Sin embargo, esta inspección preliminar permite identificar patrones fundamentales y garantizar que las transformaciones posteriores del EDA se realicen sobre una base sólida y coherentemente presentada, manteniendo consistencia entre la preparación de los datos y las visualizaciones que la acompañan. # === Analisis univariado de cada columna de df_2 === library(tidyverse) azul_main &lt;- &quot;#4A90E2&quot; azul_borde &lt;- &quot;#1F5AA6&quot; gris_linea &lt;- &quot;#5A5A5A&quot; rojo_out &lt;- &quot;#D94E4E&quot; # ---- Paleta: azul principal + neutros + acento para outliers ---- azul_main &lt;- &quot;#4A90E2&quot; # azul principal (rellenos/barras) azul_fuerte &lt;- &quot;#1F5AA6&quot; # azul mas oscuro (bordes/lineas destacadas) gris_linea &lt;- &quot;#4D4D4D&quot; # contornos/axes neutros rojo_out &lt;- &quot;#D94E4E&quot; # SOLO outliers (acento) # Crear variable acotada para claridad visual df_2 &lt;- df_2 %&gt;% mutate(tasa_fin_cap = pmin(pmax(tasa_fin, 0), 100)) # 1) Resumen estadistico general de cada columna summary(df_2) ## pais anio tasa_fin tasa_fin_cap ## Length:3004 Min. :2000 Min. : 12.19 Min. : 12.19 ## Class :character 1st Qu.:2006 1st Qu.: 84.20 1st Qu.: 84.20 ## Mode :character Median :2012 Median : 96.28 Median : 96.28 ## Mean :2011 Mean : 88.72 Mean : 87.32 ## 3rd Qu.:2017 3rd Qu.:100.00 3rd Qu.:100.00 ## Max. :2022 Max. :168.18 Max. :100.00 # 2) Analisis univariado de la variable &#39;tasa_fin_cap&#39; summary(df_2$tasa_fin_cap) ## Min. 1st Qu. Median Mean 3rd Qu. Max. ## 12.19 84.20 96.28 87.32 100.00 100.00 quantile(df_2$tasa_fin_cap, probs = c(0.01, 0.25, 0.5, 0.75, 0.99)) ## 1% 25% 50% 75% 99% ## 22.41619 84.20383 96.28211 100.00000 100.00000 # ---- Histograma + densidad ---- hist(df_2$tasa_fin_cap, breaks = seq(0, 100, by = 5), # bins uniformes, legibles col = azul_main, border = azul_fuerte, # BORDES para distinguir barras lwd = 0.8, # grosor del borde main = &quot;Distribucion global de la tasa de finalizacion primaria (0-100)&quot;, xlab = &quot;tasa_fin_cap (%)&quot;, xlim = c(0, 100)) lines(density(df_2$tasa_fin_cap), col = azul_fuerte, lwd = 2) # ---- Boxplot (relleno azul; outliers resaltados; lineas neutras) ---- boxplot(df_2$tasa_fin_cap, col = azul_main, border = gris_linea, whiskcol = gris_linea, staplecol= gris_linea, medcol = azul_fuerte, # mediana en azul fuerte outcol = rojo_out, outpch = 16, # SOLO outliers con acento main = &quot;Boxplot de la tasa de finalizacion primaria (0-100)&quot;, ylab = &quot;tasa_fin_cap (%)&quot;, ylim = c(0, 100)) # 3) Analisis univariado de la columna &#39;anio&#39; summary(df_2$anio) ## Min. 1st Qu. Median Mean 3rd Qu. Max. ## 2000 2006 2012 2011 2017 2022 range(df_2$anio) ## [1] 2000 2022 # Histograma de anio: UNA barra por anio y borde visible hist(df_2$anio, breaks = seq(2000, 2022, by = 1), # una barra por anio col = azul_main, border = azul_fuerte, # BORDES para separar barras lwd = 0.8, main = &quot;Distribucion de anios en el dataset&quot;, xlab = &quot;Anio&quot;, xaxt = &quot;n&quot;) # eje X manual para mejor legibilidad axis(side = 1, at = seq(2000, 2022, by = 2), labels = seq(2000, 2022, by = 2)) # 4) Analisis univariado de la columna &#39;pais&#39; # Cantidad de paises distintos length(unique(df_2$pais)) ## [1] 192 # Frecuencia por pais (cuantas observaciones tiene cada uno) tabla_paises &lt;- table(df_2$pais) head(tabla_paises) ## ## Afghanistan Albania Algeria Andorra ## 4 18 23 11 ## Angola Antigua and Barbuda ## 5 12 # Paises con menor y mayor cobertura head(sort(tabla_paises), 10) # Paises con menos datos ## ## Canada Korea, Dem. People&#39;s Rep. Monaco ## 1 1 1 ## South Sudan Gabon Guinea-Bissau ## 1 2 2 ## Puerto Rico (US) Sint Maarten (Dutch part) Iraq ## 2 2 3 ## Afghanistan ## 4 tail(sort(tabla_paises), 10) # Paises con mas datos ## ## Lebanon Lithuania Madagascar Malta Mexico ## 23 23 23 23 23 ## Morocco Norway Slovak Republic Sweden Switzerland ## 23 23 23 23 23 La inspección univariada del conjunto de datos revela tres patrones fundamentales. En primer lugar, la distribución de los años muestra que el período 2000–2022 está completamente cubierto, aunque la frecuencia de observaciones varía ligeramente entre años, reflejando la estructura desbalanceada del panel: algunos países aportan información de forma continua mientras otros presentan registros intermitentes. En segundo lugar, el boxplot de la tasa de finalización primaria (acotada al rango 0–100) evidencia que los valores se concentran en niveles altos, con una mediana cercana al 100%, pero también muestra una presencia notable de valores bajos y atípicos, indicando diferencias sustanciales en el desempeño educativo entre países. Finalmente, el histograma confirma visualmente este patrón: la distribución global es marcadamente asimétrica, con una fuerte acumulación de observaciones en torno a tasas elevadas y una cola hacia valores más bajos, lo que sugiere que, mientras muchos países alcanzan niveles altos de finalización primaria, un grupo significativo aún presenta rezagos importantes. 2.2 Análisis bivariado Antes de iniciar el análisis bivariado, dejamos constancia de que trabajaremos con la versión acotada de la variable objetivo (tasa_fin_cap ∈ [0,100]) para asegurar visualizaciones comparables y evitar que pocos valores extremos (&gt;100%) distorsionen escalas y patrones; la variable original (tasa_fin) se conserva y, cuando sea pertinente (p. ej., para verificar robustez), contrastaremos resultados con ella. Dado que el panel es desbalanceado (cobertura desigual por país y año), en cada contraste reportaremos el número efectivo de observaciones y el rango temporal involucrado. Asimismo, al explorar asociaciones emplearemos medidas y gráficos robustos a asimetrías y acotamientos (p. ej., correlación de Spearman además de Pearson, y bandas intercuartílicas), dejando claro que las conclusiones se interpretan condicionadas al recorte a [0,100]. Esta decisión metodológica mejora la legibilidad y la coherencia del EDA, sin renunciar a la trazabilidad de la fuente original. 2.2.1 Numérica vs Categórica # ============================================================ # Bivariado CLARO: numerica (tasa_fin_cap) vs categorica (pais) # Fig A: Lollipop-IQR por pais y quinquenio (zoom 80-100) # Fig B: % en techo (100) por pais (Top 8) # Sugerencia de chunk Rmd: {r, fig.width=11, fig.height=9} # ============================================================ suppressPackageStartupMessages({ library(dplyr); library(ggplot2); library(forcats) library(stringr); library(scales) }) # ---------- Paleta (la tuya) ---------- azul_main &lt;- &quot;#4A90E2&quot; # principal azul_borde &lt;- &quot;#1F5AA6&quot; # acento gris_linea &lt;- &quot;#4D4D4D&quot; # neutro rojo_out &lt;- &quot;#D94E4E&quot; # acento (techo/outliers) # ---------- 1) Asegurar variable acotada ---------- if (!&quot;tasa_fin_cap&quot; %in% names(df_2)) { df_2 &lt;- df_2 %&gt;% mutate(tasa_fin_cap = pmin(pmax(tasa_fin, 0), 100)) } # ---------- 2) Base 2000–2022 + quinquenios ---------- df_base &lt;- df_2 %&gt;% filter(!is.na(pais), !is.na(anio), !is.na(tasa_fin_cap), anio &gt;= 2000, anio &lt;= 2022) %&gt;% mutate( quinquenio = case_when( anio &lt;= 2004 ~ &quot;2000-2004&quot;, anio &lt;= 2009 ~ &quot;2005-2009&quot;, anio &lt;= 2014 ~ &quot;2010-2014&quot;, anio &lt;= 2019 ~ &quot;2015-2019&quot;, TRUE ~ &quot;2020-2022&quot; ), quinquenio = factor( quinquenio, levels = c(&quot;2000-2004&quot;,&quot;2005-2009&quot;,&quot;2010-2014&quot;,&quot;2015-2019&quot;,&quot;2020-2022&quot;) ) ) # ---------- 3) Top paises por cobertura ---------- N_TOP &lt;- 8 # &lt;= CLARIDAD. Si quieres 10, cambia a 10. cov_por_pais &lt;- df_base %&gt;% distinct(pais, anio) %&gt;% count(pais, name = &quot;n_anios&quot;) %&gt;% arrange(desc(n_anios)) paises_top &lt;- cov_por_pais %&gt;% slice(1:N_TOP) %&gt;% pull(pais) df_top &lt;- df_base %&gt;% filter(pais %in% paises_top) %&gt;% left_join(cov_por_pais, by = &quot;pais&quot;) %&gt;% mutate(pais_lab = str_wrap(pais, width = 18)) # ---------- 4) Resumen por pais y quinquenio ---------- res_q &lt;- df_top %&gt;% group_by(quinquenio, pais_lab) %&gt;% summarise( n = n(), med = median(tasa_fin_cap, na.rm = TRUE), p25 = quantile(tasa_fin_cap, 0.25, na.rm = TRUE), p75 = quantile(tasa_fin_cap, 0.75, na.rm = TRUE), pctcap = mean(tasa_fin_cap &gt;= 100 - 1e-9), .groups = &quot;drop&quot; ) # Para que dentro de CADA quinquenio queden ordenados por mediana (lectura natural) res_q &lt;- res_q %&gt;% group_by(quinquenio) %&gt;% mutate(pais_ord = fct_reorder(pais_lab, med, .desc = TRUE)) %&gt;% ungroup() # ============================================================ # FIG A — Lollipop-IQR por pais y quinquenio (zoom 80–100) # - linea horizontal: IQR (P25–P75) # - punto: mediana # - referencia discontinua en 100 (techo) # ============================================================ p_lollipop &lt;- ggplot(res_q, aes(x = pais_ord)) + geom_hline(yintercept = 100, linetype = &quot;dashed&quot;, color = gris_linea, linewidth = 0.5) + geom_segment(aes(xend = pais_ord, y = p25, yend = p75), color = gris_linea, linewidth = 2, alpha = 0.8) + geom_point(aes(y = med), color = azul_borde, fill = azul_main, size = 3.2, shape = 21, stroke = 0.6) + coord_flip() + facet_wrap(~ quinquenio, ncol = 3) + labs( title = &quot;tasa_fin_cap por pais (Top 8) — Mediana (punto) e IQR (segmento)&quot;, subtitle = &quot;Escala 80–100. Linea discontinua: techo (100).&quot;, x = NULL, y = &quot;tasa_fin_cap (%)&quot; ) + scale_y_continuous(limits = c(80, 100), breaks = seq(80, 100, 5), expand = expansion(mult = c(0.01, 0.03))) + theme_minimal(base_size = 12) + theme( plot.title = element_text(face = &quot;bold&quot;), axis.text.y = element_text(size = 9, lineheight = 0.9), panel.grid.minor = element_blank(), strip.text = element_text(size = 10) ) print(p_lollipop) # ============================================================ # FIG B — % en techo (100) por pais (Top 8, agregado) # ============================================================ res_cap &lt;- df_top %&gt;% group_by(pais_lab) %&gt;% summarise(pct_cap = mean(tasa_fin_cap &gt;= 100 - 1e-9), .groups = &quot;drop&quot;) %&gt;% mutate(pais_ord = fct_reorder(pais_lab, pct_cap, .desc = TRUE)) p_cap &lt;- ggplot(res_cap, aes(x = pais_ord, y = pct_cap)) + geom_col(fill = azul_main, color = gris_linea, width = 0.65) + geom_text(aes(label = percent(pct_cap, accuracy = 1)), hjust = -0.05, size = 3.5, color = gris_linea) + coord_flip(clip = &quot;off&quot;) + labs( title = &quot;Porcentaje en techo (100) por pais — Top 8&quot;, subtitle = &quot;Ordenado de mayor a menor. Indica compresion por techo.&quot;, x = NULL, y = &quot;% en 100&quot; ) + scale_y_continuous(labels = percent_format(accuracy = 1), limits = c(0, 1), expand = expansion(mult = c(0, 0.12))) + theme_minimal(base_size = 12) + theme( plot.title = element_text(face = &quot;bold&quot;), panel.grid.minor = element_blank(), axis.text.y = element_text(size = 9, lineheight = 0.9), plot.margin = margin(t = 5, r = 20, b = 5, l = 5) ) print(p_cap) En los Top 8 países, el gráfico de % en techo (100) muestra una compresión fuerte en Brunei Darussalam (96%) y Argentina (78%), moderada en Cyprus (43%), Argelia y Bulgaria (≈39%), Cabo Verde (30%) y Azerbaiyán (26%), y prácticamente nula en Cuba (0%); por tanto, en los lollipop‑IQR por quinquenio las diferencias deben leerse con cautela cuando la mediana está pegada a 100 y el IQR es mínimo (la escala está saturada). Aun así, se aprecian trayectorias: Azerbaiyán y Cabo Verde muestran alzas graduales y reducción de dispersión a lo largo de los quinquenios; Cuba se mantiene alta pero sin tocar techo, lo que permite distinguir cambios reales; Brunei y Argentina se saturan temprano y permanecen muy cerca del 100 con IQRs pequeños en los periodos recientes; Bulgaria y Cyprus se sitúan sistemáticamente altos con variabilidad baja‑moderada. En conjunto, los países convergen hacia valores elevados (IQRs más cortos en los quinquenios finales), pero el efecto techo limita la comparación fina entre los que alcanzan 100 con frecuencia. 2.2.2 Numérica vs Numérica # ===== Variable numerica vs numerica ===== library(dplyr) library(ggplot2) # Paleta azul_main &lt;- &quot;#4A90E2&quot; azul_borde &lt;- &quot;#1F5AA6&quot; gris_linea &lt;- &quot;#5A5A5A&quot; rojo_out &lt;- &quot;#D94E4E&quot; # Asegurar variable acotada if (!&quot;tasa_fin_cap&quot; %in% names(df_2)) { df_2 &lt;- df_2 %&gt;% mutate(tasa_fin_cap = pmin(pmax(tasa_fin,0),100)) } df_num &lt;- df_2 %&gt;% filter(!is.na(tasa_fin_cap), !is.na(anio), anio &gt;= 2000, anio &lt;= 2022) # ============================================================== # (A) DISPERSION GLOBAL + LOESS # ============================================================== p_disp &lt;- ggplot(df_num, aes(x = anio, y = tasa_fin_cap)) + geom_point(alpha = 0.25, color = azul_main) + geom_smooth(method = &quot;loess&quot;, se = TRUE, color = azul_borde, fill = scales::alpha(azul_main,0.3)) + labs( title = &quot;Relacion entre tasa_fin_cap y anio (dispersion global)&quot;, x = &quot;Anio&quot;, y = &quot;tasa_fin_cap (%)&quot;, subtitle = &quot;Puntos = observaciones de todos los paises. Linea LOESS indica tendencia general.&quot; ) + theme_minimal(base_size = 12) print(p_disp) # ============================================================== # (B) MEDIANA ANUAL + BANDA INTERCUARTILICA # ============================================================== df_agg &lt;- df_num %&gt;% group_by(anio) %&gt;% summarise( mediana = median(tasa_fin_cap), p25 = quantile(tasa_fin_cap, 0.25), p75 = quantile(tasa_fin_cap, 0.75), n_paises = n_distinct(pais), .groups = &quot;drop&quot; ) p_mediana &lt;- ggplot(df_agg, aes(x = anio, y = mediana)) + geom_ribbon(aes(ymin = p25, ymax = p75), fill = scales::alpha(azul_main, 0.35)) + geom_line(color = azul_borde, linewidth = 1) + geom_point(color = azul_borde, size = 2) + labs( title = &quot;Mediana anual de tasa_fin_cap con banda P25–P75&quot;, subtitle = &quot;Muestra la tendencia central y dispersion anual entre paises&quot;, x = &quot;Anio&quot;, y = &quot;tasa_fin_cap (%)&quot; ) + theme_minimal(base_size = 12) print(p_mediana) # ============================================================== # (C) MEDIA vs MEDIANA ANUAL # ============================================================== df_media &lt;- df_num %&gt;% group_by(anio) %&gt;% summarise( media = mean(tasa_fin_cap), mediana = median(tasa_fin_cap), .groups = &quot;drop&quot; ) p_mean_med &lt;- ggplot(df_media, aes(x = anio)) + geom_line(aes(y = media, color = &quot;Media&quot;), linewidth = 1) + geom_line(aes(y = mediana, color = &quot;Mediana&quot;), linewidth = 1) + scale_color_manual(values = c(&quot;Media&quot; = azul_main, &quot;Mediana&quot; = azul_borde)) + labs( title = &quot;Media vs Mediana anual de tasa_fin_cap&quot;, x = &quot;Anio&quot;, y = &quot;tasa_fin_cap (%)&quot;, color = NULL ) + theme_minimal(base_size = 12) print(p_mean_med) # ============================================================== # (D) PENDIENTE POR PAIS (MEJORA/DETERIORO) # ============================================================== df_slope &lt;- df_num %&gt;% group_by(pais) %&gt;% do({ mod &lt;- lm(tasa_fin_cap ~ anio, data = .) tibble(pendiente = coef(mod)[[&quot;anio&quot;]]) }) %&gt;% ungroup() df_slope_top &lt;- df_slope %&gt;% arrange(desc(pendiente)) %&gt;% slice(1:10) df_slope_bottom &lt;- df_slope %&gt;% arrange(pendiente) %&gt;% slice(1:10) p_slopes &lt;- ggplot(df_slope_top, aes(x = reorder(pais, pendiente), y = pendiente)) + geom_col(fill = azul_main, color = gris_linea) + coord_flip() + labs( title = &quot;Top 10 paises con mayor mejora anual (pendiente positiva)&quot;, x = NULL, y = &quot;Pendiente estimada&quot; ) + theme_minimal(base_size = 12) print(p_slopes) #### Tendencia global (dispersión + LOESS): La relación entre tasa_fin_cap y anio muestra una tendencia ascendente a lo largo de 2000–2022. El incremento es más pronunciado al inicio y luego se suaviza, con un leve aplanamiento en los años finales. La nube conserva heterogeneidad vertical en todo el periodo, evidencia de diferencias persistentes entre países. 2.2.2.1 Mediana anual y dispersión (P25–P75). La mediana anual se mantiene alta y creciente, lo que sugiere progreso sostenido. La banda intercuartílica (P25–P75) se desplaza hacia arriba y parece estrecharse ligeramente, indicando menor dispersión entre países y una convergencia parcial hacia niveles elevados de finalización. 2.2.2.2 Media vs. mediana anual. La mediana está sistemáticamente por encima de la media, lo que confirma asimetría hacia valores bajos (hay países con años de desempeño bajo que “arrastran” la media). La brecha media–mediana disminuye gradualmente, compatible con la idea de que los rezagados mejoran y la distribución se vuelve menos sesgada. 2.2.2.3 Pendiente por país (mejoras anuales). El ranking de pendientes positivas señala a varios países con mejoras anuales marcadas. Esto es coherente con dinámicas de “catch‑up”: quienes partían de niveles más bajos muestran avances más rápidos. Conviene interpretar el ranking con cautela, pues la pendiente depende de la cobertura temporal efectiva y del techo impuesto por la acotación a [0,100]. 2.3 Análisis multivariado suppressPackageStartupMessages({ library(dplyr) library(ggplot2) library(scales) library(tibble) }) # Paleta (misma que venias usando) azul_main &lt;- &quot;#4A90E2&quot; azul_borde &lt;- &quot;#1F5AA6&quot; gris_linea &lt;- &quot;#5A5A5A&quot; rojo_out &lt;- &quot;#D94E4E&quot; # --- 0) Asegurar variable acotada en [0,100] --- if (!&quot;tasa_fin_cap&quot; %in% names(df_2)) { df_2 &lt;- df_2 %&gt;% mutate(tasa_fin_cap = pmin(pmax(tasa_fin, 0), 100)) } # --- 1) Base multivariada coherente con el EDA --- df_mv &lt;- df_2 %&gt;% filter(!is.na(pais), !is.na(anio), !is.na(tasa_fin_cap), anio &gt;= 2000, anio &lt;= 2022) # --- 2) Mediana e IQR por anio (usando la variable acotada) --- dist_year &lt;- df_mv %&gt;% group_by(anio) %&gt;% summarise( med = median(tasa_fin_cap, na.rm = TRUE), p25 = quantile(tasa_fin_cap, 0.25, na.rm = TRUE), p75 = quantile(tasa_fin_cap, 0.75, na.rm = TRUE), n = n(), # util para referencia .groups = &quot;drop&quot; ) ggplot(dist_year, aes(x = anio, y = med)) + geom_ribbon(aes(ymin = p25, ymax = p75), fill = alpha(azul_main, 0.35)) + geom_line(color = azul_borde, linewidth = 1) + geom_point(color = azul_borde, size = 2) + labs( title = &quot;Mediana e IQR de tasa_fin_cap por anio&quot;, subtitle = &quot;Variable acotada en [0,100]; IQR = P25–P75&quot;, x = &quot;Anio&quot;, y = &quot;tasa_fin_cap (%)&quot; ) + scale_y_continuous(limits = c(0, 100)) + theme_minimal(base_size = 12) + theme(plot.title = element_text(face = &quot;bold&quot;), panel.grid.minor = element_blank()) # --- 3) Pendiente por pais ANTES de tocar el techo --- # Regla: # - Si el pais toca 100 en algun anio, usamos datos con anio &lt; primer anio en techo. # - Si nunca toca 100, usamos toda su serie. # - Exigimos al menos 2 puntos para estimar pendiente. slopes &lt;- df_mv %&gt;% group_by(pais) %&gt;% arrange(anio, .by_group = TRUE) %&gt;% mutate(capped = tasa_fin_cap &gt;= 100 - 1e-9) %&gt;% mutate(first_cap_year = ifelse(any(capped), min(anio[capped]), Inf)) %&gt;% # conservar todo si nunca capea; si capea, solo antes del primer techo filter(anio &lt; first_cap_year | is.infinite(first_cap_year)) %&gt;% # asegurar al menos 2 puntos por pais mutate(n_pts = n()) %&gt;% filter(n_pts &gt;= 2) %&gt;% do({ fit &lt;- lm(tasa_fin_cap ~ anio, data = .) tibble( pendiente = unname(coef(fit)[[&quot;anio&quot;]]), n_usados = nrow(.) ) }) %&gt;% ungroup() %&gt;% arrange(desc(pendiente)) # Top paises por pendiente (mejora anual antes del techo) head(slopes, 10) ## # A tibble: 10 × 3 ## pais pendiente n_usados ## &lt;chr&gt; &lt;dbl&gt; &lt;int&gt; ## 1 Azerbaijan 8.48 2 ## 2 Turks and Caicos Islands 7.07 2 ## 3 Mongolia 6.31 2 ## 4 Bhutan 4.64 5 ## 5 Tajikistan 3.82 2 ## 6 China 3.81 2 ## 7 Zambia 3.75 8 ## 8 Algeria 3.70 5 ## 9 Guinea-Bissau 3.54 2 ## 10 Syrian Arab Republic 3.51 5 El ranking de pendientes pre‑techo indica mejoras rápidas de la tasa de finalización (pp/año) en Azerbaiyán (~+8.5), Turks and Caicos (~+7.1) y Mongolia (~+6.3); sin embargo, en estos casos n_usados = 2, de modo que la “pendiente” es prácticamente la recta entre dos puntos y no es estable. Entre estimaciones más confiables (porque usan más años antes de tocar el techo) destacan Bhután (+4.64, n=5), Zambia (+3.75, n=8), Argelia (+3.70, n=5) y Siria (+3.51, n=5), que sugieren ganancias sostenidas en varios periodos; China (+3.81, n=2) vuelve a caer en el caso de evidencia escasa. Como el cálculo se hace antes de alcanzar 100 y usando la variable acotada [0–100], evitamos la subestimación por efecto techo; no obstante, cuando el tramo “pre‑techo” es muy corto o arranca desde niveles muy bajos, la pendiente puede verse inflada. Recomendación: exigir n_usados ≥ 4–5, reportar IC de la pendiente o usar un estimador robusto (Theil–Sen) y contrastar con el % en techo para interpretar correctamente los países cercanos a 100.
